# CatalogClient internals (simplified)
import httpx, os
from dataclasses import dataclass

@dataclass
class ComponentFilter:
    genai_type:  str | None = None
    lifecycle:   str | None = None
    model_tier:  str | None = None
    data_class:  str | None = None
    tags:        list[str] | None = None

class CatalogClient:
    def __init__(self):
        self._base = os.environ["BACKSTAGE_URL"]
        self._token= os.environ["BACKSTAGE_TOKEN"]

    def _headers(self): return {"Authorization": f"Bearer {self._token}"}

    def find_components(self, f: ComponentFilter) -> list[dict]:
        filters = ["kind=Component"]
        if f.genai_type:
            filters.append(f"metadata.annotations.genai.io/type={f.genai_type}")
        if f.lifecycle:
            filters.append(f"spec.lifecycle={f.lifecycle}")
        if f.model_tier:
            filters.append(f"metadata.annotations.genai.io/model-tier={f.model_tier}")
        if f.data_class:
            filters.append(f"metadata.annotations.genai.io/data-class={f.data_class}")
        resp = httpx.get(
            f"{self._base}/api/catalog/entities",
            params={"filter": ",".join(filters),
                    "fields": "metadata.name,metadata.annotations,spec.owner,spec.lifecycle"},
            headers=self._headers(),
            timeout=10,
        )
        resp.raise_for_status()
        entities = resp.json()
        # Post-filter by tags (Backstage tag filtering is OR, not AND)
        if f.tags:
            entities = [e for e in entities
                        if all(t in e.get("metadata", {}).get("tags", []) for t in f.tags)]
        return entities

    def get_component(self, name: str) -> dict:
        resp = httpx.get(
            f"{self._base}/api/catalog/entities/by-name/component/default/{name}",
            headers=self._headers(), timeout=10,
        )
        resp.raise_for_status()
        return resp.json()

