import httpx, json
from collections import defaultdict

def model_inventory() -> dict:
    # Fetch all production GenAI components
    resp = httpx.get(
        "https://backstage.internal/api/catalog/entities",
        params={
            "kind":   "Component",
            "filter": "spec.lifecycle=production,metadata.tags=genai",
            "fields": "metadata.name,metadata.annotations,spec.owner",
        },
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    entities = resp.json()

    # Tally by model
    by_model: dict[str, list[str]] = defaultdict(list)
    for e in entities:
        model = (e.get("metadata", {})
                   .get("annotations", {})
                   .get("genai.io/primary-model", "unknown"))
        by_model[model].append(e["metadata"]["name"])

    # Fetch token usage for each model from the gateway analytics API
    usage_resp = httpx.get(
        "https://analytics.internal/api/gateway-calls/by-model",
        params={"days": 30},
        headers={"Authorization": f"Bearer {TOKEN}"},
    )
    usage = {r["model_id"]: r for r in usage_resp.json().get("models", [])}

